from typing import List
from functools import lru_cache

class Solution:
    def specialPerm(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)

        # Precompute the compatibility between elements
        compatible = [[False] * n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                if i != j:
                    compatible[i][j] = nums[i] % nums[j] == 0 or nums[j] % nums[i] == 0

        @lru_cache(None)
        def dp(mask, pos):
            if mask == (1 << n) - 1:
                return 1
            total = 0
            for i in range(n):
                if not (mask & (1 << i)):
                    if compatible[pos][i]:
                        total += dp(mask | (1 << i), i)
                        total %= MOD
            return total

        result = 0
        for i in range(n):
            result += dp(1 << i, i)
            result %= MOD

        return result
